module top_module(
    input [3:0] bin,
    output [3:0] gray,
    input reset,
    input clk
);reg [3:0] invalid_gray;

always @(posedge clk) begin
    if (reset) begin
        invalid_gray <= 4'b0000;
    end else begin
        invalid_gray <= bin ^ (bin >> 1);
    end
end

assign gray = invalid_gray;

endmodule
